#include <stdio.h>
#include <unistd.h>
#include <stdint.h>
#include <pthread.h>
#include <stdlib.h>

#include "atomic.h"
#include "dt_algo.h"

// Per-device decision tree headers (generated by train_surrogate_dt.py)
// Expected names:
//   dt_weights_header/w_Trace_dev_0_dt.h
//   dt_weights_header/w_Trace_dev_1_dt.h
#include "dt_weights_header/w_Trace_dev_0_dt.h"
#include "dt_weights_header/w_Trace_dev_1_dt.h"

// Global queue length (updated by multiple threads, protected via atomics)
long queue_len;

// Historical arrays (single updater thread)
long hist_index;
long *prev_queue_len;
long *prev_latency;
long *prev_throughput;

// Per-device tree structures (populated from generated headers)
int *dt_feature_all[DEVICE_NUM] = {
    dt_feature_dev_0,
    dt_feature_dev_1,
};

long *dt_threshold_all[DEVICE_NUM] = {
    dt_threshold_dev_0,
    dt_threshold_dev_1,
};

int *dt_left_all[DEVICE_NUM] = {
    dt_left_dev_0,
    dt_left_dev_1,
};

int *dt_right_all[DEVICE_NUM] = {
    dt_right_dev_0,
    dt_right_dev_1,
};

int *dt_value_all[DEVICE_NUM] = {
    dt_value_dev_0,
    dt_value_dev_1,
};

int dt_node_count[DEVICE_NUM] = {
    DT_DEV_0_NODE_COUNT,
    DT_DEV_1_NODE_COUNT,
};

long add_fetch_cur_queue_len() {
    /*
        Return the current IO queue len.
    */
    return atomic_inc_fetch(&queue_len);   // the queue len will also count the current IO itself.
}

void inc_queue_len() {
    /*
        Increase the current queue length by 1.
    */
    atomic_inc(&queue_len);
}

void dec_queue_len() {
    /*
        Decrease the current queue length by 1.
    */
    atomic_dec(&queue_len);
}

void set_surrogate_dt(int total_io_num) {
    // 1. init the global params
    queue_len = 0;
    hist_index = 0;

    // 2. init previous queue len
    prev_queue_len = malloc(total_io_num * sizeof(long));
    for (long i = 0; i < total_io_num; i++) {
        prev_queue_len[i] = -1;    // init to `-1` to indicate invalid
    }

    // 3. init previous latency
    prev_latency = malloc(total_io_num * sizeof(long));
    for (long i = 0; i < total_io_num; i++) {
        prev_latency[i] = -1;
    }

    // 4. init previous throughput
    prev_throughput = malloc(total_io_num * sizeof(long));
    for (long i = 0; i < total_io_num; i++) {
        prev_throughput[i] = -1;
    }
}

int surrogate_dt_inference(long io_type, long size, uint32_t device, long cur_queue_len) {
    /*
        features_vec:
            // Input parameters
                0. io_type
                1. size
                2. device (implicitly used via per-device trees)
                3. cur_queue_len
            // Retrieve the following values from global historical data.
                4. prev_queue_len_1,
                5. prev_queue_len_2,
                6. prev_queue_len_3,
                7. prev_latency_1,
                8. prev_latency_2,
                9. prev_latency_3,
                10. prev_throughput_1,
                11. prev_throughput_2,
                12. prev_throughput_3
    */

    // 1. format input features, we expect the following features ordering:
    //  {io_type, size, cur_queue_len,
    //   prev_queue_len_1, prev_queue_len_2, prev_queue_len_3,
    //   prev_latency_1, prev_latency_2, prev_latency_3,
    //   prev_throughput_1, prev_throughput_2, prev_throughput_3}
    long input_vec_i[LEN_INPUT];
    for (int i = 0; i < LEN_INPUT; i++) {   // init to 0
        input_vec_i[i] = 0;
    }
    // 1.1. format io_type, io_size, and cur_queue_len
    input_vec_i[0] = io_type;
    input_vec_i[1] = size;
    input_vec_i[2] = cur_queue_len;

    // 1.2. format previous queue len, latency, and throughput
    long cur_hist_index = hist_index;
    for (int i = 1; i <= N_HIST; i ++) {
        if (cur_hist_index - i >= 0) {   // check whether we have enough historical data.
            input_vec_i[2 + i] = prev_queue_len[cur_hist_index - i];
            input_vec_i[5 + i] = prev_latency[cur_hist_index - i];
            input_vec_i[8 + i] = prev_throughput[cur_hist_index - i];

            if (prev_queue_len[cur_hist_index - i] == -1 || prev_latency[cur_hist_index - i] == -1 || prev_throughput[cur_hist_index - i] == -1) {
                printf("[Error] The historical data is not valid!");
                exit(1);
            }
        }
    }

    // 2. pick the tree of corresponding device
    if (device >= DEVICE_NUM) {
        printf("[Error] device index %u out of range (DEVICE_NUM=%d)\n", device, DEVICE_NUM);
        exit(1);
    }

    int *feature = dt_feature_all[device];
    long *threshold = dt_threshold_all[device];
    int *left = dt_left_all[device];
    int *right = dt_right_all[device];
    int *value = dt_value_all[device];
    int node_count = dt_node_count[device];

    // 3. traverse the decision tree starting from root (node 0)
    int node = 0;
    while (1) {
        if (node < 0 || node >= node_count) {
            printf("[Error] invalid node index %d (node_count=%d)\n", node, node_count);
            exit(1);
        }

        int feat = feature[node];
        if (feat < 0) {
            // leaf node
            int pred = value[node];
            if (VERBOSE) {
                printf("[dev %u] - [cur_hist_index=%ld] [leaf=%d] pred=%d\n",
                       device, cur_hist_index, node, pred);
            }
            return pred;
        }

        if (feat >= LEN_INPUT) {
            printf("[Error] feature index %d out of range (LEN_INPUT=%d)\n", feat, LEN_INPUT);
            exit(1);
        }

        long feat_val = input_vec_i[feat];
        long thr = threshold[node];

        if (feat_val <= thr) {
            node = left[node];
        } else {
            node = right[node];
        }
    }
}

void update_surrogate_dt(long io_queue_len, long io_latency, long io_throughput){
    /*
        Called by single update_thread in io_replayer.c, to insert latest completed IO's queue len
        when submitted, IO latency, and IO throughput into the historical pool.
        The historical pools to be Updated:
            prev_queue_len,
            prev_latency,
            prev_throughput,
    */

    // update previous queue len
    prev_queue_len[hist_index] = io_queue_len;

    // update previous latency
    prev_latency[hist_index] = io_latency;

    // update previous throughout
    prev_throughput[hist_index] = io_throughput;

    hist_index += 1;
}

void free_surrogate_dt() {
    /*
        Free the memory that surrogate_dt allocated
    */

    free(prev_queue_len);
    free(prev_latency);
    free(prev_throughput);
}

